1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	const CURSE_RATE = 0.5;
4	const BLOCK_SIZE = 3;
5	const BLOCK_PREMIUM = 60;
6	
7	const BASE_PREMIUMS: Record<string, number> = {
8	  sword: 100,
9	  amulet: 60,
10	  staff: 80,
11	  potion: 40,
12	  rune: 25,
13	  moonstone: 25,
14	};
15	
16	type Item = { type: string; cursed?: boolean };
17	
18	const COMPONENT_TYPES = ["rune", "moonstone"];
19	
20	const isComponent = (item: Item): boolean => COMPONENT_TYPES.includes(item.type);
21	
22	const sum = (values: number[]): number =>
23	  values.reduce((total, value) => total + value, 0);
24	
25	const sumOfBasePremiums = (items: Item[]): number =>
26	  sum(items.map((item) => BASE_PREMIUMS[item.type]));
27	
28	const groupByType = (items: Item[]): Item[][] => {
29	  const groups: Record<string, Item[]> = {};
30	  for (const item of items) {
31	    if (!groups[item.type]) groups[item.type] = [];
32	    groups[item.type].push(item);
33	  }
34	  return Object.values(groups);
35	};
36	
37	const basePremiumForComponentGroup = (group: Item[]): number =>
38	  group.length === BLOCK_SIZE ? BLOCK_PREMIUM : sumOfBasePremiums(group);
39	
40	const basePremiumFor = (items: Item[]): number => {
41	  const components = items.filter(isComponent);
42	  const nonComponents = items.filter((item) => !isComponent(item));
43	  const componentGroupPremiums = groupByType(components).map(basePremiumForComponentGroup);
44	  return sum(componentGroupPremiums) + sumOfBasePremiums(nonComponents);
45	};
46	
47	const curseSurchargeFor = (items: Item[]): number =>
48	  sum(items.filter((item) => item.cursed).map((item) => BASE_PREMIUMS[item.type] * CURSE_RATE));
49	
50	const quotePremium = (base: number, curseSurcharge: number): number =>
51	  Math.ceil(base + curseSurcharge + base * FIRST_INSURANCE_RATE + PROCESSING_FEE);
52	
53	export const runScenario = (scenario: any): unknown => {
54	  const items = scenario.steps[0].items;
55	  const base = basePremiumFor(items);
56	  const curseSurcharge = curseSurchargeFor(items);
57	  return { results: [{ premium: quotePremium(base, curseSurcharge) }] };
58	};
