const curseSurchargeForItem = (item: Item): number =>
  item.cursed ? BASE_PREMIUMS[item.type] * CURSE_RATE : 0;

const curseSurchargeFor = (items: Item[]): number =>
  sum(items.map(curseSurchargeForItem));

const quotePremium = (items: Item[]): number => {
  const base = basePremiumFor(items);
  const curseSurcharge = curseSurchargeFor(items);
  return Math.ceil(base + curseSurcharge + base * FIRST_INSURANCE_RATE + PROCESSING_FEE);
};

export const runScenario = (scenario: any): unknown => {
  const items = scenario.steps[0].items;
  return { results: [{ premium: quotePremium(items) }] };
};
